import{_ as o,o as t,c as a,ah as r}from"./chunks/framework.Bi9enVNS.js";const u=JSON.parse('{"title":"What Is Virtual Log Trace","description":"","frontmatter":{},"headers":[],"relativePath":"en/intro/what-is-vlt.md","filePath":"en/intro/what-is-vlt.md","lastUpdated":1774205896000}'),i={name:"en/intro/what-is-vlt.md"};function l(s,e,c,d,n,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="what-is-virtual-log-trace" tabindex="-1">What Is Virtual Log Trace <a class="header-anchor" href="#what-is-virtual-log-trace" aria-label="Permalink to &quot;What Is Virtual Log Trace&quot;">​</a></h1><p>Virtual Log Trace, or VLT, is a protocol-first visual log tracing reference implementation. It is not just an architecture sketch. The repository already wires together the protocol, ingestion endpoint, query APIs, sample sender, and frontend workbench into a runnable stack.</p><h2 id="the-problem-it-addresses" tabindex="-1">The problem it addresses <a class="header-anchor" href="#the-problem-it-addresses" aria-label="Permalink to &quot;The problem it addresses&quot;">​</a></h2><p>Many systems can emit logs with a <code>trace_id</code>, but they still lack a shared upload contract, explicit source modeling, and a simple way to explore multi-source logs as one trace. VLT closes that loop:</p><ul><li>Upload: one batch protocol and validation model</li><li>Storage: a normalized record shape for every accepted log</li><li>Query: logs, trace detail, timeline, topology, and source inventory</li><li>UI: one Trace Workbench that links those views together</li></ul><h2 id="what-is-already-in-the-repository" tabindex="-1">What is already in the repository <a class="header-anchor" href="#what-is-already-in-the-repository" aria-label="Permalink to &quot;What is already in the repository&quot;">​</a></h2><ul><li><code>proto/vlt/common/v1/common.proto</code></li><li><code>proto/vlt/logs/v1/logs.proto</code></li><li><code>proto/vlt/ingest/v1/ingest.proto</code></li><li><code>POST /v1/logs</code></li><li><code>GET /v1/logs/search</code>, <code>GET /v1/traces/{trace_id}</code>, <code>GET /v1/traces/{trace_id}/timeline</code>, <code>GET /v1/traces/{trace_id}/topology</code>, <code>GET /v1/sources</code></li><li>Go server in <code>cmd/vlt-server</code></li><li>Go sender in <code>cmd/vlt-sender</code></li><li>React Trace Workbench in <code>web/</code></li></ul><h2 id="good-fits-for-the-project" tabindex="-1">Good fits for the project <a class="header-anchor" href="#good-fits-for-the-project" aria-label="Permalink to &quot;Good fits for the project&quot;">​</a></h2><ul><li>Validate a custom log upload protocol</li><li>Add a real trace browsing loop to a demo or prototype</li><li>Align on fields and UI flows before investing in persistence, auth, or indexing</li><li>Use it as a concrete reference for source modeling and topology derivation</li></ul><h2 id="what-it-is-not" tabindex="-1">What it is not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What it is not&quot;">​</a></h2><ul><li>Not a full production-grade observability platform</li><li>Not a durable log store</li><li>Not a replacement for the full OpenTelemetry ecosystem</li><li>Not a dependency discovery engine; current topology is inferred from adjacent source segments inside a trace</li></ul><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>README.md</code></li><li><code>proto/vlt/*/v1/*.proto</code></li><li><code>cmd/vlt-server/main.go</code></li><li><code>web/src/App.jsx</code></li></ul>',13)])])}const m=o(i,[["render",l]]);export{u as __pageData,m as default};
